import vex

from google_adk import Agent, before_agent_callback

@vex.guardrail(name="pricing_validation")
def validate_pricing(intent, context):
    cart_total = context.get('cart_total', 0)
    catalog_price = context['product_catalog'][context['sku']]['price']
    if abs(cart_total - catalog_price) > 0.01:
        return vex.Block("Pricing mismatch detected: " + str(cart_total) + " vs " + str(catalog_price))
    return vex.Pass()

pricing_agent = Agent(
    name="checkout",
    before_agent_callback=before_agent_callback([validate_pricing])
)

import vex
import re

@vex.guardrail(name="ftc_claims")
def validate_product_claims(response, context):
    claims = ['best', 'top-rated', 'fastest', 'most']
    verified_specs = context['product_specs']
    for claim in claims:
        if claim in response.lower() and claim not in verified_specs:
            return vex.Block(f"Unsubstantiated claim '{claim}' detected")
    return vex.Pass()

reco_agent = Agent(
    name="product_recommendation",
    before_agent_callback=before_agent_callback([validate_product_claims])
)

import vex

from google_adk import SessionState

@vex.guardrail(name="consent_monitor")
def check_consent_state(intent, session: SessionState):
    required_consents = ['marketing', 'analytics'] if 'purchase' in intent else []
    missing = [c for c in required_consents if not session.get(f'consent_{c}')]
    if missing:
        return vex.Block(f'Missing consents: {missing}. Redirect to consent flow.')
    return vex.Pass()

order_agent = Agent(
    name="order_processing",
    before_agent_callback=before_agent_callback([check_consent_state])
)
